"use client";

import {
  useWalletTransactions,
  useWalletTransactionsSummary,
} from "@/shared/api/query-hooks/use-wallet";
import {
  TransactionDirection,
  TransactionType,
  type WalletTransaction,
} from "@/shared/types/payment.types";
import { Badge } from "@/shared/ui/badge";
import { Loader } from "@/shared/ui/loader";
import { useState } from "react";
import { ChevronBackOutline, ChevronForwardOutline } from "react-ionicons";

const ITEMS_PER_PAGE = 20;

function getTransactionTypeLabel(transaction: WalletTransaction): string {
  switch (transaction.type) {
    case TransactionType.DEPOSIT:
      return "Deposit";
    case TransactionType.BUYBACK_REPAYMENT:
      return "Buyback Payment";
    case TransactionType.LOAN_DISBURSEMENT:
      return "Loan Disbursement";
    case TransactionType.FEE_PAYMENT:
      return "Fee Payment";
    default:
      return transaction.description || transaction.type;
  }
}

function getPaidWithLabel(transaction: WalletTransaction): string {
  const prefix =
    transaction.userEntry.direction === TransactionDirection.CREDIT
      ? "Paid to"
      : "Paid with";
  const method = transaction.paymentMethod?.displayName || "Bank Acc.(***)";
  return `${prefix}: ${method}`;
}

function TransactionStatusBadge({
  status,
}: {
  status: WalletTransaction["status"];
}) {
  if (status === "completed") {
    return (
      <Badge variant="success" className="bg-[#ECFDF5] text-[#047857]">
        Completed
      </Badge>
    );
  }
  if (status === "failed") {
    return (
      <Badge variant="error" className="bg-[#FEE2E2] text-[#B91C1C]">
        Failed
      </Badge>
    );
  }
  return (
    <Badge variant="warning">
      {status.charAt(0).toUpperCase() + status.slice(1)}
    </Badge>
  );
}

const TABLE_HEADERS = [
  "Transaction ID",
  "Transaction Type",
  "Paid With / To",
  "Amount",
  "Date",
  "Status",
];

function PaginationFooter({
  showingFrom,
  showingTo,
  total,
  hasPrevPage,
  hasNextPage,
  onPrev,
  onNext,
}: {
  showingFrom: number;
  showingTo: number;
  total: number;
  hasPrevPage: boolean;
  hasNextPage: boolean;
  onPrev: () => void;
  onNext: () => void;
}) {
  return (
    <div className="flex items-center justify-between px-1">
      <span className="font-new-sans text-sm text-[#A8A29E]">
        Showing {showingFrom}–{showingTo} of {total} transactions
      </span>
      <div className="flex items-center gap-2">
        <button
          type="button"
          onClick={onPrev}
          disabled={!hasPrevPage}
          className="flex h-9 w-9 items-center justify-center rounded-lg border border-[#D6D3D1] bg-[#F5F3EF] text-[#44403C] transition-opacity disabled:opacity-40"
        >
          <ChevronBackOutline width="16px" height="16px" />
        </button>
        <button
          type="button"
          onClick={onNext}
          disabled={!hasNextPage}
          className="flex h-9 w-9 items-center justify-center rounded-lg border border-[#D6D3D1] bg-[#F5F3EF] text-[#44403C] transition-opacity disabled:opacity-40"
        >
          <ChevronForwardOutline width="16px" height="16px" />
        </button>
      </div>
    </div>
  );
}

function TransactionSummaryCard({
  label,
  value,
  isLoading,
}: {
  label: string;
  value: string | number;
  isLoading: boolean;
}) {
  return (
    <div className="flex flex-col gap-2 rounded-xl border border-[#D6D3D1] bg-[#F5F3EF] px-6 py-4">
      <span className="font-new-sans text-sm text-[#A8A29E]">{label}</span>
      {isLoading ? (
        <div className="h-8 w-24 animate-pulse rounded bg-[#E5E1DB]" />
      ) : (
        <span className="font-new-serif text-2xl font-light leading-[120%] text-[#44403C]">
          {value}
        </span>
      )}
    </div>
  );
}

export function PaymentHistory() {
  const [skip, setSkip] = useState(0);
  const { data, isLoading } = useWalletTransactions({
    limit: ITEMS_PER_PAGE,
    skip,
  });
  const { data: summary, isLoading: summaryLoading } =
    useWalletTransactionsSummary();

  const handleNextPage = () => {
    setSkip((prev) => prev + ITEMS_PER_PAGE);
  };

  const handlePrevPage = () => {
    setSkip((prev) => Math.max(0, prev - ITEMS_PER_PAGE));
  };

  const transactions = data?.data || [];
  const total = data?.total || 0;
  const hasNextPage = skip + ITEMS_PER_PAGE < total;
  const hasPrevPage = skip > 0;
  const showingFrom = total === 0 ? 0 : skip + 1;
  const showingTo = Math.min(skip + ITEMS_PER_PAGE, total);

  const paginationProps = {
    showingFrom,
    showingTo,
    total,
    hasPrevPage,
    hasNextPage,
    onPrev: handlePrevPage,
    onNext: handleNextPage,
  };

  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-col items-center gap-2 text-center">
        <h1 className="font-new-serif text-3xl font-light leading-[120%] text-[#44403C]">
          Transaction History
        </h1>
        <p className="font-new-sans text-sm text-[#A8A29E]">
          Find historical records of your received and made payments.
        </p>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
        <TransactionSummaryCard
          label="Lifetime Permanent Sale Offers"
          value={summary?.lifetimePermanentSaleOffers ?? 0}
          isLoading={summaryLoading}
        />
        <TransactionSummaryCard
          label="Lifetime Completed Buyback Offers"
          value={summary?.lifetimeCompletedBuybackOffers ?? 0}
          isLoading={summaryLoading}
        />
        <TransactionSummaryCard
          label="All Time Declined or Expired Offers"
          value={summary?.allTimeDeclinedOrExpiredOffers ?? 0}
          isLoading={summaryLoading}
        />
        <TransactionSummaryCard
          label="Lifetime Payments Received"
          value={
            summary?.lifetimePaymentsReceived
              ? `${summary.lifetimePaymentsReceived.currency}${summary.lifetimePaymentsReceived.amountDollars.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
              : "0"
          }
          isLoading={summaryLoading}
        />
      </div>

      {isLoading ? (
        <div className="flex h-[400px] items-center justify-center">
          <Loader />
        </div>
      ) : transactions.length === 0 ? (
        <div className="flex items-center justify-center rounded-2xl border border-[#D6D3D1] py-20">
          <p className="font-new-sans text-lg text-[#A8A29E]">
            No transactions yet
          </p>
        </div>
      ) : (
        <>
          {/* Desktop table — hidden on mobile */}
          <div className="hidden flex-col gap-4 md:flex">
            <div className="overflow-hidden rounded-xl border border-[#D6D3D1]">
              <table className="w-full">
                <thead>
                  <tr
                    style={{
                      background:
                        "linear-gradient(0deg, rgba(255,255,255,0.6), rgba(255,255,255,0.6)), #EDE9E3",
                    }}
                  >
                    {TABLE_HEADERS.map((header) => (
                      <th
                        key={header}
                        className="px-4 py-3 text-left font-new-sans text-sm font-medium text-[#44403C]"
                      >
                        {header}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {transactions.map((transaction) => (
                    <tr
                      key={transaction.id}
                      className="border-t border-[#D6D3D1] bg-[#F5F3EF]"
                    >
                      <td className="px-4 py-3 font-new-sans text-sm text-[#44403C]">
                        #{transaction.id.slice(0, 9)}
                      </td>
                      <td className="px-4 py-3 font-new-sans text-sm text-[#44403C]">
                        {getTransactionTypeLabel(transaction)}
                      </td>
                      <td className="px-4 py-3 font-new-sans text-sm text-[#44403C]">
                        {transaction.paymentMethod?.displayName ||
                          "Bank Acc.(***)"}
                      </td>
                      <td className="px-4 py-3 font-new-sans text-sm text-[#44403C]">
                        $ {transaction.userEntry.amountDollars.toFixed(2)}
                      </td>
                      <td className="px-4 py-3 font-new-sans text-sm text-[#44403C]">
                        {new Date(transaction.createdAt).toLocaleDateString(
                          "en-US",
                          {
                            day: "numeric",
                            month: "long",
                            year: "numeric",
                          },
                        )}
                      </td>
                      <td className="px-4 py-3">
                        <TransactionStatusBadge status={transaction.status} />
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <PaginationFooter {...paginationProps} />
          </div>

          {/* Mobile cards — hidden on desktop */}
          <div className="flex flex-col gap-4 md:hidden">
            <span className="font-new-sans text-sm font-medium text-[#44403C]">
              My Transactions
            </span>

            <div className="flex flex-col divide-y divide-[#D6D3D1] rounded-xl border border-[#D6D3D1] bg-[#F5F3EF]">
              {transactions.map((transaction) => (
                <div key={transaction.id} className="flex flex-col gap-1 p-4">
                  <div className="flex items-center justify-between">
                    <span className="font-new-sans text-xs text-[#A8A29E]">
                      #{transaction.id.slice(0, 9)}
                    </span>
                    <TransactionStatusBadge status={transaction.status} />
                  </div>
                  <span className="font-new-sans text-sm font-medium text-[#44403C]">
                    {getTransactionTypeLabel(transaction)}
                  </span>
                  <span className="font-new-sans text-xs text-[#A8A29E]">
                    {getPaidWithLabel(transaction)}
                  </span>
                  <span className="font-new-sans text-sm text-[#44403C]">
                    $ {transaction.userEntry.amountDollars.toFixed(2)}
                  </span>
                  <span className="font-new-sans text-xs text-[#A8A29E]">
                    {new Date(transaction.createdAt).toLocaleDateString(
                      "en-US",
                      {
                        day: "numeric",
                        month: "long",
                        year: "numeric",
                      },
                    )}
                  </span>
                </div>
              ))}
            </div>

            <PaginationFooter {...paginationProps} />
          </div>
        </>
      )}
    </div>
  );
}
